parameters.jsCode:
// No partitions to archive
return [{
  json: {
    message: 'No partitions older than 7 years found',
    action: 'none',
    timestamp: new Date().toISOString()
  }
}];

// Prepare archive data
const partitionName = $('Find Old Partitions').first().json.partition_name;
const rows = $input.all();

// Convert to JSONL format
const jsonlContent = rows.map(r => r.json.json_row).join('\n');

return [{
  json: {
    partition_name: partitionName,
    row_count: rows.length,
    archive_content: jsonlContent,
    archive_filename: `${partitionName}.jsonl`,
    timestamp: new Date().toISOString()
  }
}];

parameters.query:
