-- WARNING: Only run after confirming archive was saved!
DROP TABLE IF EXISTS audit.{{ $json.partition_name }};

parameters.jsCode:
// Final summary
const archiveData = $('Prepare Archive').first().json;

return [{
  json: {
    message: 'Archive prepared (file storage not configured)',
    partition: archiveData.partition_name,
    rows_exported: archiveData.row_count,
    note: 'Enable Drop Partition node after configuring file storage',
    timestamp: new Date().toISOString()
  }
}];
